/**
 * Generate an expression representing a simple variable declaration.
 * @function VariableDeclaration
 * @param {string} kind The variable's kind (string, number, object, etc)
 * @param {string} name The name to give to the delcared variable.
 * @param {any} [initializer] An AST expression of the right-hand-side of the declaration (=), if given.
 * @return {any} The generated variable-declaration expression.
 * @intdocs
 */
export default (kind:string, name:string, initializer?:any): any => {
    const declaration = {
        type: "VariableDeclaration",
        declarations: [
            {
                type: "VariableDeclarator",
                id: {
                    type: "Identifier",
                    name
                }
            }
        ],
        kind
    };
    if(initializer) {
        (declaration.declarations[0] as any).init = initializer;
    }
    return declaration;
};
