/**
 * Generate an expression representing a function expression that returns
 * an object expression.
 * @function FunctionExpression
 * @param {object} objectExpression The object expression returned by the generated function.
 * @param {string} objectExpression.type
 * @param {any[]} objectExpression.properties
 * @param {Boolean} hasSelf Whether or not the function declares a `self`
 * @return {Object} The generated function expression.
 * @intdocs
 */
export default function FunctionExpression(objectExpression:{type: string, properties: any[]}, hasSelf:Boolean):Object {
    const params =
        hasSelf
            ? [
                {
                    type: 'Identifier',
                    name: 'self'
                }
            ]
            : [];
    return {
        type: 'FunctionExpression',
        id: null,
        params,
        defaults: [],
        body: {
            type: 'BlockStatement',
            body: [
                {
                    type: 'ReturnStatement',
                    argument: objectExpression
                }
            ]
        },
        rest: null,
        generator: false,
        expression: false
    };
}
