import LiteralExpression from './LiteralExpression';

/**
 * Generate an expression representing a Javascript Object.
 * Instantiate, then add keys and values, and reference `expression`.
 * @class ObjectExpression
 * @param {any[]} [props] Initial properties of the generated object.
 * @intdocs
 */
class ObjectExpression {

    /**
     * The generated object expression.
     * @name ObjectExpression#expression
     * @type {object}
     * @property {string} type
     * @property {any[]} properties
     */
    public expression:{
        type:string,
        properties:any[]
    };

    constructor(props?:any) {
        this.expression = {
            type: "ObjectExpression",
            properties: props ? props : []
        };
    }

    /**
     * Add a property with the given key and value to the object expression.
     * @method ObjectExpression#addKeyValue
     * @param {string} key The key of the property.
     * @param {any} value The value of the property.
     */
    addKeyValue(key:string, value:any):void {
        this.expression.properties.push({
            type: "Property",
            key: LiteralExpression(key),
            value: value,
            kind: "init",
            method: false,
            shorthand: false
        });
    }
}

export default ObjectExpression;
