import LiteralExpression from './LiteralExpression';

/**
 * Generate an expression representing an arrow function which returns a
 * `require` statement to the passed-in module path.
 * @function ArrowFunctionReturnRequire
 * @param  {string} relativePath The path to the module to require in the body.
 * @return {any} The arrow function expression.
 * @intdocs
 */
export default (relativePath:string):any => {
    return {
        type: "ArrowFunctionExpression",
        id: null,
        params: [],
        defaults: [],
        body: {
            type: "BlockStatement",
            body: [
                {
                    type: "ReturnStatement",
                    argument: {
                        type: "CallExpression",
                        callee: {
                            type: "Identifier",
                            name: "require"
                        },
                        arguments: [LiteralExpression(relativePath)]
                    }
                }
            ]
        },
        generator: false,
        expression: false
    };
};
