import FunctionExpression from './FunctionExpression';

/**
 * Create an expression to represent a function call with object parameters.
 * @function CallExpression
 * @param {object} objectExpression The object containing the parameters to pass.
 * @param {string} objectExpression.type
 * @param {any[]} objectExpression.properties
 * @param {Boolean} hasSelf Whether or not to pass args to the call expression.
 * @return {any} The call expression generated.
 * @intdocs
 */
export default function CallExpression(objectExpression:{type: string, properties: any[]}, hasSelf:Boolean):any {
    const args =
        hasSelf
            ? [
                {
                    type: 'ObjectExpression',
                    properties: []
                }
            ]
            : [];
    return {
        type: 'CallExpression',
        callee: FunctionExpression(objectExpression, hasSelf),
        arguments: args
    };
}
