/**
 * Generate an expression representing a simple object-property value reference.
 * @function SimpleMemberExpression
 * @param {string} objectIdentifier The name of the object (left of the dot).
 * @param {string} propertyIdentifier The name of the property (right of the dot).
 * @return {any} The generated object-property reference expression.
 * @intdocs
 */
export default (objectIdentifier:string, propertyIdentifier:string):any => {
    return {
        type: "MemberExpression",
        computed: false,
        object: {
            type: "Identifier",
            name: objectIdentifier
        },
        property: {
            type: "Identifier",
            name: propertyIdentifier
        }
    };
};
