import VariableDeclaration from './VariableDeclaration';

/**
 * Generate an expression representing a constant declaration and assignment
 * to a new class instance, with parameters passed to the constructor.
 * @function ConstFromNew
 * @param {string} name The name of the constant instantiated.
 * @param {string} className The name of the class to instantiate.
 * @param {any[]} args The arguments passed to the class's constructor.
 * @return {any} The generated representation of the declaration statement.
 * @intdocs
 */
export default (name:string, className:string, args:any[]):any => {
    return VariableDeclaration("const", name, {
        type: "NewExpression",
        callee: {
            type: "Identifier",
            name: className
        },
        arguments: args
    });
};
