/**
 * @function LiteralExpression
 * @param {string} value The value of the expression to generate.
 * @return {any} The generated literal expression.
 * @intdocs
 */
export default function LiteralExpression(value:string):any {
    return {
        type: "Literal",
        value: value,
        raw: "\"" + value + "\""
    };
}
