/**
 * Generate an expression to represent an {Array<any>}.
 * Instantiate, then push items onto the array, and reference `expression`.
 * @class ArrayExpression
 * @intdocs
 * @property constructor {ArrayExpression#expression}
 */
class ArrayExpression {

    /**
     * The generated expression
     * @name ArrayExpression#expression
     * @type {Object}
     * @property type {string}
     * @property elements {any[]}
     */
    public expression:{
        type:string,
        elements:any[]
    };

    constructor() {
        this.expression = {
            type: "ArrayExpression",
            elements: []
        };
    }

    /**
     * Add an item to the array.
     * @param {any} value The item to push onto the array.
     * @method ArrayExpression#push
     */
    public push(value:any):void {
        this.expression.elements.push(value);
    }
}

export default ArrayExpression;
