import LiteralExpression from './LiteralExpression';
import VariableDeclaration from './VariableDeclaration';

/**
 * Generate an expression representing a module require statement.
 * @function RequireModule
 * @param {string} name The name of the constant to declare for the module.
 * @param {string} moduleNameOrPath The name or path to the module to require.
 * @return {any} The generated representation of the require statement.
 * @intdocs
 */
export default (name:string, moduleNameOrPath:string):any => {
    return VariableDeclaration("const", name, {
        type: "CallExpression",
        callee: {
            type: "Identifier",
            name: "require"
        },
        arguments: [
            LiteralExpression(moduleNameOrPath)
        ]
    });
};
